class Solution:
    def findTheLongestSubstring(self, s: str) -> int:
        mask = 0
        first = {0: -1}
        max_len = 0
        vowel_bit = {'a': 1, 'e': 2, 'i': 4, 'o': 8, 'u': 16}
        for i, ch in enumerate(s):
            if ch in vowel_bit:
                mask ^= vowel_bit[ch]
            if mask in first:
                max_len = max(max_len, i - first[mask])
            else:
                first[mask] = i
        return max_len
```
